Hi

Sorry for not replying too long.

It's been a while that I created a workaround for our situation. The workaround replaces saveAs, works similarly but solves the FF/jwplayer issue. 
As I re-read my comment, the main issue was (see same comment in code below):

**Important:** document.createEvent() and initEvent() are deprecated and do not work on FF when jwplayer is included. Thereby, we use the MouseEvent constructor which works properly on Chrome and FF.


I packed things into a AngularJS directive (still pretty hacky). The described issue above should be easy to fix in saveAs.
```
function arrayBufferToBase64( buffer ) {
    var binary = '';
    var bytes = new Uint8Array( buffer );
    var len = bytes.byteLength;
    for (var i = 0; i < len; i++) {
        binary += String.fromCharCode( bytes[ i ] );
    }
    return window.btoa( binary );
}

function downloadData(scope, $http) {
    scope.$emit('download-start');
    return $http.get(env.editor_api_public_path + '/getDocx/'+ scope.exportType + "/" + scope.exportId, { responseType: 'arraybuffer' })
    .success(function(data, status, headers, config) {
        var base64 = arrayBufferToBase64(data);
        var filename = (headers('Content-Disposition').match('filename="([^"]*)"'))[1];
        scope.$emit('downloaded', base64, filename);
    })
    .error(function(status, data) {
        console.log(status);
        console.log(data);
    });
};

appDirectives.directive('exportDocx', ['$timeout', '$compile', '$http', function($timeout, $compile, $http) {
    return {
        restrict: 'E',
        replace: true,
        transclude: true,
        template: '<a href="" ng-click="downloadData()"></a>',
        scope: {
            //title: '@',         // evaluated
            exportId: '=',      // two-way
            exportType: '@',    // evaluated
            //glyphicon: '@'      // evaluated
        },
        link: function(scope, element, attrs, ctrl, transclude) {
            var anchor = element;

            transclude(function (clone) {
                if (clone.length) {
                    anchor.html(clone);
                }
            });

            // When the download starts, disable the link
            scope.$on('download-start', function() {
                $(anchor).attr('disabled', 'disabled');
            });

            // When the download finishes, attach the data to the link (data-URI) and trigger automatically a mouse click on the link.
            // After the automatic mouse click, the data (data-URI) is detached from the link and the initial attributes are restored.
            scope.$on('downloaded', function(event, data, filename) {
                $(anchor).attr('href', 'data:application/vndopenxmlformats-officedocumentwordprocessingmldocument;charset=utf-8;base64,' + data)
                    .attr('download', filename)
                    .removeAttr('disabled');

                // attention, the following order is very important

                // 1) detach downloadData function in order to avoid download loops
                scope.downloadData = function() {};

                // 2) put mouse click event into event queue 
                //    (automatically click on the link, which href points now to a dataURI containing the file encoded as Base64 string)
                $timeout(function() {
                    // Important: document.createEvent() and initEvent() are deprecated and do not work on FF when jwplayer is included.
                    // Thereby, we use the MouseEvent constructor which works properly on Chrome and FF.
                    var evt = new MouseEvent('click', {
                        'view': window,
                        'bubbles': true,
                        'cancelable': false
                    });
                    element[0].dispatchEvent(evt);
                }, 0);

                // 3) reattach downloadData and initialize link attributes correctly for the next "manually" triggered
                // click on the hyperlink
                $timeout(function() {
                    scope.downloadData = function() {downloadData(scope, $http)};

                    // restore attributes on link
                    $(anchor).attr('href', '')
                        .removeAttr('download')
                        .removeAttr('disabled');
                }, 0);
            });
        },
        controller: ['$scope', '$attrs', '$http', function($scope, $attrs, $http) {
            $scope.downloadData = function() {downloadData($scope, $http);};
        }] 
    }
}]);
```

