This worked well for me:
```
    async def arun(self, query):
        with self.driver.session(access_mode=neo4j.v1.READ_ACCESS) as session:
            def run():
                return session.run(query).records()
            it = await self.loop.run_in_executor(self.executor, run)

            def iterate():
                try:
                    return next(it)
                except StopIteration:
                    return None
            while True:
                res = await self.loop.run_in_executor(self.executor, iterate)
                if res is None:
                    return
                else:
                    yield dict(res)
```

